#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_STR_LEN 100

typedef struct {
    char **data;
    int size;
    int capacity;
} StringList;

void init_list(StringList *list) {
    list->data = NULL;
    list->size = 0;
    list->capacity = 0;
}

void free_list(StringList *list) {
    for (int i = 0; i < list->size; i++) {
        free(list->data[i]);
    }
    free(list->data);
    list->size = 0;
    list->capacity = 0;
}

void push_back(StringList *list, const char *s) {
    if (list->size >= list->capacity) {
        int new_capacity = list->capacity == 0 ? 1 : list->capacity * 2;
        list->data = realloc(list->data, new_capacity * sizeof(char *));
        list->capacity = new_capacity;
    }
    list->data[list->size] = strdup(s);
    list->size++;
}

int contains(StringList *list, const char *s) {
    for (int i = 0; i < list->size; i++) {
        if (strcmp(list->data[i], s) == 0) {
            return 1;
        }
    }
    return 0;
}

